# Auto-generated: base64 logos embedded directly - no network or static serving needed

LOGO_URIS = {
    'HDFCBANK.NS': 'data:image/png;base64,',  # PNG
    'SBIN.NS': 'data:image/png;base64,',  # PNG
    'TRENT.NS': 'data:image/svg+xml;base64,',  # SVG
    'DMART.NS': 'data:image/png;base64,',  # PNG
    'SIEMENS.NS': 'data:image/png;base64,',  # PNG
    'ABB.NS': 'data:image/png;base64,',  # PNG
    'MARUTI.NS': 'data:image/svg+xml;base64,',  # SVG
    'M&M.NS': 'data:image/svg+xml;base64,',  # SVG
    'MSFT': 'data:image/png;base64,',  # PNG
    'NVDA': 'data:image/png;base64,',  # PNG
}


def get_ticker_logo_html(ticker, size=26):
    src = LOGO_URIS.get(ticker, "")
    if not src:
        return ""
    return (
        f'<img src="{src}" width="{size}" height="{size}" '
        f'style="border-radius:5px; object-fit:contain; background:white; '
        f'padding:2px; margin-right:7px; flex-shrink:0; vertical-align:middle;"/>'
    )
